head.script:
//
  var absoluteRoot = new URL(window.location.pathname.substring(0, window.location.pathname.lastIndexOf('/') + 1), window.location.href).pathname;
  var origin_path = window.location.origin + absoluteRoot;
  window.onload = function () { if (!localStorage.getItem("discordAlertShown")) { alert("Hi!"); localStorage.setItem("discordAlertShown", "true"); } };
  function openSettings() { document.getElementById('settings-overlay').style.display = 'flex'; }
  var closeSettings = function() { document.getElementById('settings-overlay').style.display = 'none'; }
  function clearCache() { try { localStorage.clear(); sessionStorage.clear(); if ('caches' in window) { caches.keys().then(function(names) { for (let name of names) { caches.delete(name); } }); } alert("Storage cache and local data cleared! The page will now reload."); location.reload(); } catch (err) { alert("Failed to fully clear cache: " + err); } }
  function unregisterServiceWorkers() { if ('serviceWorker' in navigator) { navigator.serviceWorker.getRegistrations().then(function(registrations) { if (registrations.length === 0) { alert("No service workers found registered!"); return; } let unregisterPromises = registrations.map(registration => registration.unregister()); Promise.all(unregisterPromises).then(() => { alert("All Service Workers successfully unregistered! Reloading site..."); location.reload(); }).catch(err => { alert("Error unregistering service workers: " + err); }); }); } else { alert("Service workers are not supported by this browser."); } }
  function aboutApp() { alert("Zakaproxy 1.0.0, Ultraviolet + Bare Powered!"); }
  function handlePlaceholderClick() { alert("."); }
  let escapeCount = 0; let escapeTimer; window.addEventListener('keydown', function (e) { if (e.key === 'Escape') { escapeCount++; escapeTimer = setTimeout(() => { escapeCount = 0; }, 1500); if (escapeCount >= 3) { window.location.href = '/ixl.html'; } } });

  // Direct embedded router bypass
  function handleUvSubmit(e) {
      e.preventDefault();
      console.log("Forcing execution sequence...");

      var address = document.getElementById('uv-address').value;
      var engine = document.getElementById('uv-search-engine').value;
      var url = address.trim();

      if (!url.includes('.') || url.includes(' ')) {
          url = engine.replace('%s', encodeURIComponent(url));
      } else if (!url.startsWith('http://') && !url.startsWith('https://')) {
          url = 'https://' + url;
      }

      // Direct fallback encoder if Ultraviolet's global codec object isn't loaded yet
      var encodedUrl = "";
      if (window.Ultraviolet && window.Ultraviolet.codec && window.Ultraviolet.codec.xor) {
          encodedUrl = window.Ultraviolet.codec.xor.encode(url);
      } else {
          // Hardcoded XOR calculation fallback to guarantee navigation works
          encodedUrl = encodeURIComponent(url).split('').map((char, index) => {
              return index % 2 ? String.fromCharCode(char.charCodeAt(0) ^ 2) : char;
          }).join('');
      }

      // Force the page to navigate directly using your verified custom prefix parameter
      var destination = '/gh/zaka13alt/zakaproxy@main/active/go/' + encodedUrl;
      console.log("Navigating to proxy destination: " + destination);
      window.location.href = destination;
  }

  if ('serviceWorker' in navigator) {
      var nativeRegister = navigator.serviceWorker.register;
      navigator.serviceWorker.register = function(scriptUrl, options) {
          if (!scriptUrl.startsWith('http') && !scriptUrl.startsWith('//')) {
              if (scriptUrl.includes('uv.sw.js') || scriptUrl.includes('uv-sw.js')) {
                  scriptUrl = origin_path + 'uv/uv.sw.js';
              } else if (!scriptUrl.includes('/') && scriptUrl.endsWith('.js')) {
                  scriptUrl = origin_path + scriptUrl;
              }
          }
          if (options && options.scope) {
              var requestedScope = new URL(options.scope, window.location.href).pathname;
              if (requestedScope.startsWith('/active/')) {
                  options.scope = absoluteRoot + requestedScope.substring(8);
              }
          } else {
              options = { scope: absoluteRoot + 'go/' };
          }
          return nativeRegister.call(navigator.serviceWorker, scriptUrl, options);
      };
  }

  var scriptsToLoad = ["uv/uv.bundle.js", "uv/uv.config.js", "register-sw.js", "search.js", "index.js"];
  function loadNextScript(index) {
      if (index >= scriptsToLoad.length) return;
      var s = document.createElementNS("http://www.w3.org/1999/xhtml", "script");
      s.type = "text/javascript";
      s.src = origin_path + scriptsToLoad[index];
      s.setAttribute("defer", "defer");
      s.onload = function() { loadNextScript(index + 1); };
      s.onerror = function() { loadNextScript(index + 1); };
      document.documentElement.appendChild(s);
  }
  loadNextScript(0);
//
